using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
        // Preserve "Discriminator" for compatibility with 500K existing documents
        // and direct SQL queries that reference c.Discriminator.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve the old "Product|123" format so existing documents stay readable.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // EF Core 9: HasIndex throws for Cosmos entities (was silently ignored).
        // Removed — manage indexing via Azure Portal / Bicep / Terraform instead.
        // WAS: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

